}

// ---------------------------------------------------------------------------
// Helper Lemmas
// ---------------------------------------------------------------------------

lemma SumsLength(x: seq<int>, y: seq<int>)
  requires |x| == |y|
  ensures |Sums(x, y)| == |x|
  decreases |x|
{
  if |x| > 0 {
    SumsLength(x[..|x|-1], y[..|y|-1]);
  }
}

lemma SumsElement(x: seq<int>, y: seq<int>, k: int)
  requires |x| == |y|
  requires 0 <= k < |x|
  ensures |Sums(x, y)| == |x|
